#[derive(Debug, Clone)]
struct TaskExecutorStatus {
    enabled: bool,
    worker_id: String,
    poll_interval_ms: u64,
    status: String,
    last_tick_at: Option<String>,
    last_task_id: Option<String>,
    last_message: String,
    completed_count: u64,
    failure_count: u64,
}

impl TaskExecutorStatus {
    fn new(enabled: bool) -> Self {
        let count = if enabled { task_executor_worker_count() } else { 0 };
        Self {
            enabled,
            worker_id: if count > 1 {
                format!("{TASK_EXECUTOR_WORKER_ID}-0..{count}")
            } else {
                TASK_EXECUTOR_WORKER_ID.to_string()
            },
            poll_interval_ms: TASK_EXECUTOR_POLL_INTERVAL_MS,
            status: if enabled { "starting" } else { "disabled" }.to_string(),
            last_tick_at: None,
            last_task_id: None,
            last_message: if enabled {
                "Worker executor locale in avvio.".to_string()
            } else {
                "Worker executor locale disabilitato da ambiente.".to_string()
            },
            completed_count: 0,
            failure_count: 0,
        }
    }
}

